;(function(){System.register([],function(exports,module){'use strict';return{execute:function(){(Drupal2=>{const odsCustomSubmenu={elements:{submenuLinks:document.querySelectorAll("[data-submenu-wrapper] [data-submenu-item] [data-submenu-link]")},constants:{activeClass:"ods-submenu__nav__item__link--active"},methods:{initialize:()=>{odsCustomSubmenu.elements.submenuLinks.forEach(link=>{if(link.getAttribute("href")===window.location.href){link.classList.add(odsCustomSubmenu.constants.activeClass);}else{link.classList.remove(odsCustomSubmenu.constants.activeClass);}});}},attach:()=>{odsCustomSubmenu.methods.initialize();}};Drupal2.behaviors.odsCustomSubmenu=odsCustomSubmenu;})(Drupal);}};});})();
